#include <iostream>
#include <vector>
#include <string>

int main(int argc, char** argv) {
    std::vector<std::string> args(argv, argv + argc);

    // Print each argument with its index
    for (size_t i = 0; i < args.size(); i++) {
        std::cout << "arg[" << i << "] = "
                  << args[i] << "\n";
    }
    return 0;
}

function fibonacci(n) {
    if (n <= 1) return n;
    let a = 0, b = 1;
    for (let i = 2; i <= n; i++) {
        [a, b] = [b, a + b];
    }
    return b;
}

fn factorial(n: u64) -> u64 {
    match n {
        0 | 1 => 1,
        _ => n * factorial(n - 1),
    }
}
